var e=[{id:`L2_1`,type:`dialog`,speaker:`GUARD_NPC_POISONRAT_NULL`,text:{KOREA:`끄으으…`,JPN:`くうぅ……`,ENG:`Kkhhhkkk...`,TWN:`呃呃…`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`GUARD_NPC_POISONRAT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`이제 당신뿐이에요. 저항은 포기하시죠.`,JPN:`残りはあなただけです。抵抗はやめてください。`,ENG:`You're the only one left now. Give up.`,TWN:`只剩你一個了，放棄無謂的抵抗吧！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`BARTENDER_NPC_POISONRAT_A`,text:{KOREA:`칫, 웃기지 마! 이쪽도 이판사판이라고!`,JPN:`チッ、冗談じゃねえぞ！　こっちだって一か八だ！`,ENG:`Grr, stuff you! I'd rather die!`,TWN:`嘖，你做夢！我們已經退無可退！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_NPC_POISONRAT_A`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`BARTENDER_NPC_POISONRAT_A`,text:{KOREA:`보스! 보초팀이 전부 당했습니다! 어서 인질을 데리고 자릴 피하십쇼!`,JPN:`ボス！　見張りが全員やられました！　早く人質を連れてお逃げください！`,ENG:`Boss! All our guards are down! Take the hostage and leave!`,TWN:`老大！哨兵組已經全部陣亡！你快帶人質逃走！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_NPC_POISONRAT_A`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`NOISE_VOICE_NULL_NULL`,text:{KOREA:`이■… 저건…■■ 무슨 ■…!`,JPN:`しまっ■……あれは……■いったい■■……！`,ENG:`Oh, n■... What the ■■ll's going ■n?`,TWN:`惡■…是怎…■■回■…！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_NPC_POISONRAT_A`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`BARTENDER_NPC_POISONRAT_A`,text:{KOREA:`뭐야? 통신 상태가 왜 이러지?`,JPN:`なんだ？　通信状態がおかしいぞ！`,ENG:`What? What's wrong with the connection?`,TWN:`訊號怎麼這樣？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_NPC_POISONRAT_A`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`BARTENDER_NPC_POISONRAT_A`,text:{KOREA:`커헉……!`,JPN:`……ぐわっ！`,ENG:`Khhhkk!`,TWN:`噢嗚……！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_NPC_POISONRAT_A`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`휴우…….`,JPN:`ふう……`,ENG:`Phew...`,TWN:`呼……`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`악마도 아닌 사람들을 상대로 이렇게까지 싸우다니… 돌아가면 많이 혼나겠네요.`,JPN:`悪魔でもない人間を相手にここまでやってしまって……
帰ったらとても怒られてしまいそうです。`,ENG:`I'm fighting people instead of devils... Father won't be happy if he finds out.`,TWN:`結果我的對手不是魔鬼而是人…回去一定會被罵死！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`으앗?!`,JPN:`わあっ！？`,ENG:`Ah?`,TWN:`嗯？！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`이 진동은 뭐죠?`,JPN:`この振動は何でしょう？`,ENG:`Why is the building shaking all of a sudden?`,TWN:`怎麼會有震動？`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`…불길하네요.`,JPN:`……嫌な予感がします。`,ENG:`This is not good.`,TWN:`…我有不好的預感！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`서둘러야겠어요!`,JPN:`急がないと！`,ENG:`I'd better hurry!`,TWN:`動作要快點！`},stage:{bg:`CORRIDOR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`조금만 기다려요.`,JPN:`少しだけ待ってください。`,ENG:`Just hang in there, Momo!`,TWN:`再等我一下！`},stage:{bg:`GREMORY_BAR`,slots:{L:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L29_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`제발… 무사해야 돼요.`,JPN:`どうか……無事でありますように。`,ENG:`Please... Please be safe.`,TWN:`拜託你…千萬不能有事！`},stage:{bg:`GREMORY_BAR`,slots:{L:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`MOMO_BAR_NULL_NULL`,face:`UNIT_LAUGH`}}}}];export{e as default};